insert into sys_permissions (id, tenant_id, code, name, module, built_in, created_at, updated_at) select '00000000-0000-4000-8000-000000002504', 'default', 'project:delete', '项目删除', 'project', true, current_timestamp, current_timestamp where not exists (select 1 from sys_permissions where tenant_id='default' and code='project:delete');
insert into sys_role_permissions (role_id, permission_id) select r.id,p.id from sys_roles r join sys_permissions p on p.tenant_id=r.tenant_id where r.code='ADMIN' and p.code='project:delete' and not exists (select 1 from sys_role_permissions x where x.role_id=r.id and x.permission_id=p.id);
